	public void testConnection(){
		try {
			String content = JGet.wget("http://www.google.com", 4000, 4000);
			Assert.assertFalse(content.isEmpty());
		} catch (Exception e) {
			e.printStackTrace();
			Assert.fail("Could not connect to google.com");
		}
